// Parse AI agent output into qargo_payload. On JSON error, flag review.
const out = [];
for (const it of $input.all()) {
  const raw = it.json.output || it.json.text || it.json.response || '';
  let payload = null, review = false, reason = null;
  try {
    const s = String(raw).trim();
    const json = s.startsWith('{') ? s : (s.match(/\{[\s\S]*\}/) || [null])[0];
    payload = json ? JSON.parse(json) : null;
  } catch (e) { review = true; reason = 'ai_parse_error: ' + e.message; }
  if (!payload) { review = true; reason = reason || 'ai_no_json'; }
  if (payload && payload.needs_review === true) { review = true; reason = 'ai_flagged_review'; }
  out.push({ json: { ...it.json, qargo_payload: payload, needs_review: review, review_reason: reason, parser: 'ai-fallback' } });
}
return out;

// Validate qargo_payload against minimum Qargo schema before upload.
function validate(p){const e=[];if(!p||typeof p!=='object')e.push('not object');if(!p?.order_identifier)e.push('order_identifier');if(!p?.customer)e.push('customer');if(!p?.pickup_stop?.location)e.push('pickup_stop.location');if(!p?.delivery_stop?.location)e.push('delivery_stop.location');if(!Array.isArray(p?.goods)||p.goods.length===0)e.push('goods[]');return{ok:e.length===0,errors:e};}
const out=[];
for(const it of $input.all()){const p=it.json.qargo_payload;const v=validate(p);out.push({json:{...it.json,payload_valid:v.ok,payload_errors:v.errors,needs_review:it.json.needs_review||!v.ok,review_reason:it.json.review_reason||(!v.ok?'schema_invalid: '+v.errors.join(','):null)}});}
return out;

/**
 * lib/validate_upload.js – Validate Qargo's upload response.
 *
 * DROP-IN n8n CODE NODE BODY.
 *   Replaces the existing "Validate Upload" node in the V8 workflow.
 *   Mode: "Run Once for All Items"
 *
 * The old node checked only HTTP status. This one also requires a non-empty
 * echo of the order_identifier; otherwise it flags for Review.
 */

const out = [];
for (const item of $input.all()) {
  const resp   = item.json.response || item.json.body || item.json;
  const status = item.json.statusCode || item.json.status || item.json.response?.status;

  const sentId = item.json.qargo_payload?.order_identifier
               || item.json.order_identifier
               || null;

  const qargoId = resp?.order_identifier
               || resp?.data?.order_identifier
               || resp?.id
               || resp?.order?.order_identifier
               || null;

  const httpOk = (status >= 200 && status < 300) || status === undefined;

  const ok = httpOk && !!qargoId && (!sentId || String(qargoId) === String(sentId) || !!resp?.success);

  out.push({
    json: {
      ...item.json,
      upload_ok: ok,
      upload_http_status: status,
      qargo_order_id: qargoId,
      upload_error: ok ? null : (
        !httpOk ? `HTTP ${status}` :
        !qargoId ? 'Qargo response missing order_identifier' :
        `Qargo echoed ${qargoId} but we sent ${sentId}`
      ),
    },
  });
}
return out;

/**
 * lib/finalize.js – Finalize Import (idempotent wrap-up).
 *
 * DROP-IN n8n CODE NODE BODY.
 *   Replaces the existing "Finalize Import" node in the V8 workflow.
 *   Mode: "Run Once for All Items"
 *
 * Decides the routing outcome:
 *   outcome === 'upload'   → proceed to Store Memory → Track Processed → Mark Read → Move to Client Folder
 *   outcome === 'review'   → Move to Review → Track Processed (stops there, not marked read)
 *   outcome === 'ignore'   → Mark Read → Track Processed
 *
 * Track Processed MUST be the last write so the mail is re-tryable on
 * transient failures upstream.
 */

const out = [];
for (const item of $input.all()) {
  const uploadOk     = item.json.upload_ok === true;
  const importStatus = item.json.import_status || item.json.response?.status || null;
  const needsReview  = item.json.needs_review === true
                     || item.json.ignore_gate === 'review'
                     || item.json.review       === true;
  const shouldIgnore = item.json.ignore_gate === 'ignore'
                     || item.json.ignore      === true;

  let outcome;
  if (shouldIgnore)                            outcome = 'ignore';
  else if (!uploadOk || needsReview)           outcome = 'review';
  else if (importStatus && /failed|error/i.test(importStatus)) outcome = 'review';
  else                                         outcome = 'upload';

  out.push({
    json: {
      ...item.json,
      outcome,
      finalize_reason:
        outcome === 'upload' ? 'Qargo upload + import confirmed'
      : outcome === 'review' ? (item.json.upload_error || 'needs manual review')
      : 'customer marked ignore',
      finalize_ts: new Date().toISOString(),
    },
  });
}
return out;

// Track Processed — MUST be the last write per ARCHITECTURE invariant #1.
// Replace this Code node with a Data Table 'insert row' node that stores:
//   internetMessageId, processed_at, outcome, customer, qargo_order_id, review_reason
// The current body just logs; swapping it out preserves connections.
const out=[];
for(const it of $input.all()){
  const row={
    internetMessageId: it.json.mail_id_for_dedupe || it.json.mail?.internetMessageId || null,
    processed_at: new Date().toISOString(),
    outcome: it.json.outcome || null,
    customer: it.json.customer || null,
    qargo_order_id: it.json.qargo_order_id || null,
    review_reason: it.json.review_reason || it.json.finalize_reason || null,
  };
  out.push({ json: { ...it.json, tracked_row: row } });
}
return out;
